## 代码语法高亮

### TypeScript

```typescript
interface TreeNode<T> {
  value: T;
  left: TreeNode<T> | null;
  right: TreeNode<T> | null;
}

function inorderTraversal<T>(root: TreeNode<T> | null): T[] {
  if (!root) return [];
  return [
    ...inorderTraversal(root.left),
    root.value,
    ...inorderTraversal(root.right),
  ];
}
```

### Python

```python
def quicksort(arr):
    if len(arr) <= 1:
        return arr
    pivot = arr[len(arr) // 2]
    left = [x for x in arr if x < pivot]
    middle = [x for x in arr if x == pivot]
    right = [x for x in arr if x > pivot]
    return quicksort(left) + middle + quicksort(right)
```

### Rust

```rust
fn main() {
    let numbers = vec![34, 12, 5, 99, 1, 78];
    let sorted = quicksort(&numbers);
    println!("{:?}", sorted);
}

fn quicksort(arr: &[i32]) -> Vec<i32> {
    if arr.len() <= 1 {
        return arr.to_vec();
    }
    let pivot = arr[arr.len() / 2];
    let mut left = Vec::new();
    let mut middle = Vec::new();
    let mut right = Vec::new();
    for &x in arr {
        if x < pivot { left.push(x); }
        else if x == pivot { middle.push(x); }
        else { right.push(x); }
    }
    let mut result = quicksort(&left);
    result.extend(middle);
    result.extend(quicksort(&right));
    result
}
```

