```typescript
interface Post {
  title: string;
  date: string;
  tags: string[];
}

function getLatestPost(posts: Post[]): Post | null {
  if (posts.length === 0) return null;
  return posts.sort((a, b) =>
    new Date(b.date).getTime() - new Date(a.date).getTime()
  )[0];
}
```

